import{bQ as a,aL as i,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"主从复制","description":"","frontmatter":{},"headers":[],"relativePath":"05.Redis/05-主从复制.md","filePath":"05.Redis/05-主从复制.md","lastUpdated":null}'),n={name:"05.Redis/05-主从复制.md"};function p(l,s,h,d,k,r){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="主从复制" tabindex="-1">主从复制 <a class="header-anchor" href="#主从复制" aria-label="Permalink to &quot;主从复制&quot;">​</a></h1><p>Redis 主从复制把主库的数据变更同步到一个或多个从库。写请求进主库，主库把变更流推给从库。从库通常用于读扩展、故障切换候选节点和备份源。</p><p>Redis 的复制不是强一致的——主库写入成功返回后，从库可能还没来得及收到这条变更。主库突然故障时，最后一段数据可能丢失。复制提供的是&quot;副本&quot;和&quot;恢复基础&quot;，不是数据库级别的强一致事务。</p><p>主从复制里几个词经常一起出现：</p><table tabindex="0"><thead><tr><th>名词</th><th>含义</th><th>排查时看哪里</th></tr></thead><tbody><tr><td>master / primary</td><td>接收写请求的主库</td><td><code>INFO replication</code> 里的 <code>role:master</code></td></tr><tr><td>replica</td><td>跟随主库同步数据的从库</td><td><code>role:slave</code>、<code>master_link_status</code></td></tr><tr><td>offset</td><td>复制偏移量，可以理解成主从各自同步到的位置</td><td><code>master_repl_offset</code>、<code>slave_repl_offset</code></td></tr><tr><td>backlog</td><td>主库维护的复制积压缓冲区，保存最近一段增量命令</td><td><code>repl_backlog_active</code>、<code>repl_backlog_size</code></td></tr><tr><td>RDB 全量同步</td><td>从库拿到一份完整快照后重新加载</td><td>日志里的 <code>Full resync</code>、<code>BGSAVE</code></td></tr></tbody></table><h2 id="一、复制建立的过程" tabindex="-1">一、复制建立的过程 <a class="header-anchor" href="#一、复制建立的过程" aria-label="Permalink to &quot;一、复制建立的过程&quot;">​</a></h2><p>从库连接主库后，根据情况走全量复制或部分复制：</p><p><strong>全量复制</strong>（从库初次连接，或复制积压缓冲区里缺失了对应数据）：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20replica%5B%22%E4%BB%8E%E5%BA%93%E8%BF%9E%E6%8E%A5%E4%B8%BB%E5%BA%93%22%5D%20--%3E%20fork%5B%22%E4%B8%BB%E5%BA%93%20fork%3Cbr%2F%3E%E7%94%9F%E6%88%90%20RDB%22%5D%0A%20%20%20%20fork%20--%3E%20send%5B%22%E5%8F%91%E9%80%81%20RDB%3Cbr%2F%3E%E5%88%B0%E4%BB%8E%E5%BA%93%22%5D%0A%20%20%20%20send%20--%3E%20load%5B%22%E4%BB%8E%E5%BA%93%E5%8A%A0%E8%BD%BD%20RDB%22%5D%0A%20%20%20%20load%20--%3E%20incr%5B%22%E7%BB%A7%E7%BB%AD%E6%8E%A5%E6%94%B6%20RDB%20%E4%B9%8B%E5%90%8E%3Cbr%2F%3E%E4%BA%A7%E7%94%9F%E7%9A%84%E5%A2%9E%E9%87%8F%E5%91%BD%E4%BB%A4%22%5D%0A"></div><p>全量复制期间，主库的 fork 和 RDB 传输都会消耗资源。如果从库很多且同时发起全量复制（比如所有从库同时重启），主库的压力是叠加的。</p><p><strong>部分复制</strong>（网络短暂断开后重连，且断开期间的数据还在 backlog 里）：从库上报自己当前的 offset，主库从 backlog 里把缺失的那段增量发过去。不会触发全量复制。</p><p>相关配置：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 复制积压缓冲区——主库维护一个环形缓冲区，记录最近的写命令</span></span>
<span class="line"><span># 从库重连后如果 offset 还在缓冲区范围内，就只补增量；否则走全量复制</span></span>
<span class="line"><span>repl-backlog-size 256mb</span></span>
<span class="line"><span>repl-backlog-ttl 3600</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 全量复制时直接通过 socket 发送 RDB，不额外落盘（对磁盘慢的机器更友好）</span></span>
<span class="line"><span># 默认 no——主库先把 RDB 写到磁盘文件，再发给从库。磁盘慢时这个&quot;先写盘&quot;步骤是瓶颈</span></span>
<span class="line"><span>repl-diskless-sync yes</span></span></code></pre></div><p><code>repl-backlog-size</code> 的估算思路：写入速率 × 期望容忍的最大断开时间。如果主库每秒写入 10MB，期望 60 秒内的断链都能走部分复制，backlog 至少需要 10MB × 60 = 600MB。设太小频繁全量复制，设太大浪费内存。</p><h2 id="二、配置主从" tabindex="-1">二、配置主从 <a class="header-anchor" href="#二、配置主从" aria-label="Permalink to &quot;二、配置主从&quot;">​</a></h2><p>主库 <code>192.168.10.11</code>：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bind 127.0.0.1 192.168.10.11</span></span>
<span class="line"><span>port 6379</span></span>
<span class="line"><span>appendonly yes    # 主库建议开启持久化，否则重启后内存空、同步给从库也空</span></span></code></pre></div><p>从库 <code>192.168.10.129</code>：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bind 127.0.0.1 192.168.10.129</span></span>
<span class="line"><span>port 6379</span></span>
<span class="line"><span>replicaof 192.168.10.11 6379    # 启动后自动连接主库建立复制</span></span>
<span class="line"><span>appendonly yes</span></span></code></pre></div><p>如果主库有密码，从库需要配 <code>masterauth</code>：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>masterauth strong_password_here</span></span></code></pre></div><p>也可以在运行时动态建立或取消复制关系：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 让当前实例成为从库</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> REPLICAOF</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 让从库脱离复制，变成独立主库（故障切换时会用到）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> REPLICAOF</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ONE</span></span></code></pre></div><p>运行时命令适合临时操作，但持久化配置要写进配置文件——不然重启后会恢复到配置文件里定义的拓扑。</p><h2 id="三、查看复制状态" tabindex="-1">三、查看复制状态 <a class="header-anchor" href="#三、查看复制状态" aria-label="Permalink to &quot;三、查看复制状态&quot;">​</a></h2><p>主库：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replication</span></span></code></pre></div><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>role:master</code></td><td>当前角色是主库</td></tr><tr><td><code>connected_slaves</code></td><td>已连接的从库数量</td></tr><tr><td><code>master_repl_offset</code></td><td>主库当前的复制偏移量——每写入一条命令 offset 就增长</td></tr><tr><td><code>repl_backlog_active</code></td><td>复制积压缓冲区是否正在使用</td></tr></tbody></table><p>从库：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replication</span></span></code></pre></div><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>role:slave</code></td><td>当前角色是从库</td></tr><tr><td><code>master_host</code></td><td>主库地址</td></tr><tr><td><code>master_link_status</code></td><td>up 或 down——链路是否正常</td></tr><tr><td><code>master_last_io_seconds_ago</code></td><td>最近一次收到主库数据距今多少秒</td></tr><tr><td><code>slave_repl_offset</code></td><td>从库当前回放到的 offset</td></tr></tbody></table><p>判断延迟的核心方法是对比主从的 offset：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 主库上</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replication</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> master_repl_offset</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从库上</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replication</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slave_repl_offset</span></span></code></pre></div><p>两者的差值就是当前未同步的字节量。差值持续扩大说明从库追不上主库——可能的原因：网络带宽不够、从库 CPU 或磁盘慢、主库写入量太大、从库正在做 BGSAVE 或 AOF 重写抢了资源。</p><h2 id="四、从库只读" tabindex="-1">四、从库只读 <a class="header-anchor" href="#四、从库只读" aria-label="Permalink to &quot;四、从库只读&quot;">​</a></h2><p>从库默认只读：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replica-read-only yes</span></span></code></pre></div><p>这能防止应用误写从库。故障切换时（Sentinel 或手动），新主库会取消这个限制。</p><p>主从链路断开时，从库的行为由 <code>replica-serve-stale-data</code> 控制：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replica-serve-stale-data yes   # 断开后继续响应读请求（读到的可能是旧数据）</span></span></code></pre></div><p>设为 <code>no</code> 则断开后大多数命令直接报错。保留 <code>yes</code> 的好处是读扩展仍然可用（读到的数据只是旧一点而非错误）；坏处是应用可能读到过时的数据而不自知。配置类、榜单类场景读旧一点通常能接受；库存、锁状态这类读旧数据可能造成业务错误。</p><h2 id="五、读写分离的应用要点" tabindex="-1">五、读写分离的应用要点 <a class="header-anchor" href="#五、读写分离的应用要点" aria-label="Permalink to &quot;五、读写分离的应用要点&quot;">​</a></h2><p>读写分离的典型路径：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20app%5B%22%E5%BA%94%E7%94%A8%22%5D%20--%3E%20write%5B%22%E5%86%99%E8%AF%B7%E6%B1%82%22%5D%0A%20%20%20%20app%20--%3E%20read%5B%22%E8%AF%BB%E8%AF%B7%E6%B1%82%22%5D%0A%20%20%20%20write%20--%3E%20master%5B%22Redis%20%E4%B8%BB%E5%BA%93%22%5D%0A%20%20%20%20master%20--%3E%20repl%5B%22%E5%BC%82%E6%AD%A5%E5%A4%8D%E5%88%B6%E6%B5%81%22%5D%0A%20%20%20%20repl%20--%3E%20replica%5B%22Redis%20%E4%BB%8E%E5%BA%93%22%5D%0A%20%20%20%20read%20--%3E%20replica%0A"></div><p>核心问题是复制延迟——刚写到主库的数据，去从库读可能还没到。处理方式分场景：</p><table tabindex="0"><thead><tr><th>场景</th><th>适合读从库</th><th>不适合</th></tr></thead><tbody><tr><td>首页配置、排行榜、统计</td><td>延迟几秒不影响展示</td><td>—</td></tr><tr><td>备份导出</td><td>避免主库直接承受备份读取</td><td>—</td></tr><tr><td>大量读请求分摊</td><td>读多写少，能容忍短暂延迟</td><td>—</td></tr><tr><td>刚写完马上要读到</td><td>—</td><td>复制延迟导致读到旧值</td></tr><tr><td>库存扣减、余额判断</td><td>—</td><td>一致性要求高</td></tr><tr><td>分布式锁状态</td><td>—</td><td>延迟会破坏互斥判断</td></tr></tbody></table><p>业务如果要求&quot;读己之写&quot;（刚写入的数据立即能读到），写之后的读请求要发给主库，或者在应用层做短时间的主库读标记。</p><h2 id="六、复制安全参数——控制写入的-副本门槛" tabindex="-1">六、复制安全参数——控制写入的&quot;副本门槛&quot; <a class="header-anchor" href="#六、复制安全参数——控制写入的-副本门槛" aria-label="Permalink to &quot;六、复制安全参数——控制写入的&quot;副本门槛&quot;&quot;">​</a></h2><p>主库可以配置：在从库数量不足或延迟过高时拒绝写入。目的是降低主库&quot;孤岛写入&quot;的风险：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>min-replicas-to-write 1      # 至少 1 个从库满足条件才允许写</span></span>
<span class="line"><span>min-replicas-max-lag 10      # 从库延迟超过 10 秒就不算&quot;满足条件&quot;</span></span></code></pre></div><p>这个配置的取舍很清楚：从库全部异常时，主库会拒绝写入——宁愿短时间写失败，也不让主库在没有副本的情况下持续写入，因为一旦主库在这期间宕机，这些数据就永久丢失了。对数据安全性要求高的核心系统会开这个参数；纯缓存场景通常不开，因为这等于让从库的可用性绑架了主库的可用性。</p><p>单次写入后也可以用 <code>WAIT</code> 命令确认副本接收情况：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order:1001</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status:paid</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> WAIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 等至少 1 个从库确认收到，最多等 1000ms</span></span></code></pre></div><p><code>WAIT</code> 返回实际确认的从库数量。返回 0 说明超时前没有从库确认——但写入在主库上已经成功了。这不是事务回滚，业务代码要处理&quot;主库写成功但副本未确认&quot;的中间状态。</p><h2 id="七、复制异常排查" tabindex="-1">七、复制异常排查 <a class="header-anchor" href="#七、复制异常排查" aria-label="Permalink to &quot;七、复制异常排查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>排查方向</th></tr></thead><tbody><tr><td><code>master_link_status:down</code></td><td>网络不通、主库密码错、防火墙拦截、主库 bind 没绑从库能连到的地址</td></tr><tr><td>反复全量复制</td><td>backlog 太小、网络频繁抖动、从库频繁重启</td></tr><tr><td>从库延迟持续扩大</td><td>主库写入量超出从库处理能力、网络带宽瓶颈、从库在做 BGSAVE/AOF rewrite</td></tr><tr><td>从库连不上主库</td><td><code>ss -lntp</code> 确认主库监听地址、安全组/防火墙规则、<code>masterauth</code> 密码、protected-mode</td></tr></tbody></table><p>排查步骤：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从库侧测试主库端口是否可达</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从库侧测试密码是否正确</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;strong_password_here&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PING</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看主从双方日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/redis/redis-6379.log</span></span></code></pre></div><p>复制异常时把 <code>INFO replication</code> 的完整输出保存下来——它记录了当时的角色、offset、链路状态和从库数量，复盘时不用靠猜。</p><h2 id="八、从库做备份" tabindex="-1">八、从库做备份 <a class="header-anchor" href="#八、从库做备份" aria-label="Permalink to &quot;八、从库做备份&quot;">​</a></h2><p>从库常被用来承担备份任务，避免主库执行 <code>BGSAVE</code> 时的 fork 影响主库性能：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BGSAVE</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> persistence</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rdb_last_bgsave_status</span></span></code></pre></div><p>但从库备份的前提是从库延迟不大——如果从库已经落后很多，备份出来的 RDB 也落后同样多。备份前检查从库状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replication</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;master_link_status|master_last_io_seconds_ago&#39;</span></span></code></pre></div><p><code>master_link_status</code> 为 up 且 <code>master_last_io_seconds_ago</code> 在几秒以内，备份的数据才算&quot;够新&quot;。备份成功和数据够新是两件事。</p><h2 id="九、手工切换的基本步骤" tabindex="-1">九、手工切换的基本步骤 <a class="header-anchor" href="#九、手工切换的基本步骤" aria-label="Permalink to &quot;九、手工切换的基本步骤&quot;">​</a></h2><p>Sentinel 或 Cluster 自动切换之前，手工切换是排查和演练的基础：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 在选定的从库上提升为主库</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> REPLICAOF</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ONE</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 确认新主库角色</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replication</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> role</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 旧主库恢复后，作为新主库的从库加入，避免双主写入</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> REPLICAOF</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span></span></code></pre></div><p>手工切换最麻烦的不是这几条命令，而是应用连接怎么切到新主库、旧主库残留的写入怎么处理、其他从库要不要改挂新主。切完之后除了 <code>PING</code>，还要做一次写入验证确认新主库确实可写。</p>`,69)])])}const F=a(n,[["render",p]]);export{c as __pageData,F as default};
